def perceive(data):
    # data: a structured claim-intake record. Maps the claim type to its statutory
    # period (overridable by an explicit period_days) and reads an accrual day.
    periods = {
        "personal_injury": 730,
        "breach_of_contract": 1460,
        "fraud": 1095,
        "defamation": 365,
        "property_damage": 1095,
        "medical_malpractice": 913,
    }
    out = {}
    if "period_days" in data:
        out["limitations_period_days"] = int(data["period_days"])
    elif data.get("claim_type") in periods:
        out["limitations_period_days"] = int(periods[data["claim_type"]])
    if "accrual_day" in data:
        out["accrual_day"] = int(data["accrual_day"])
    return out
